//! `grove fetch` — pull grammars from the hosted registry into the OS cache.
//!
//! Host model: a `grove-registry` GitHub repo served via jsDelivr's GitHub CDN,
//! laid out as `<host>/index.json` (the catalog) and `<host>/<lang>/{grammar.wasm,
//! tags.scm, manifest.json}`. Each wasm's sha256 is verified against the catalog
//! before it lands in the cache. Override the host with `GROVE_REGISTRY_URL`.

use std::io::Read;

use anyhow::{anyhow, bail, Context, Result};
use serde::Deserialize;

use crate::registry;
use crate::registry::sha256;

/// Default host for the catalog + per-language text files (tags.scm, manifest).
/// raw.githubusercontent serves these reliably (jsDelivr's per-file cold-fetch
/// 502s intermittently). The heavy wasm binaries are GitHub Release assets (see
/// `release_base` in the catalog), so this stays light. Override with
/// `GROVE_REGISTRY_URL` to self-host or mirror.
const DEFAULT_HOST: &str = "https://raw.githubusercontent.com/Entelligentsia/grove-registry/v1";

#[derive(Deserialize)]
struct Catalog {
    /// Base URL for release-asset files (GitHub Releases); needed if any file
    /// entry has an `asset`.
    #[serde(default)]
    release_base: Option<String>,
    #[serde(default)]
    grammars: Vec<CatEntry>,
}

#[derive(Deserialize)]
struct CatEntry {
    name: String,
    version: String,
    /// File extensions this grammar handles (schema 2+); used by `grove init`
    /// to detect a project's languages before any grammar is fetched.
    #[serde(default)]
    extensions: Vec<String>,
    /// filename → where/what to fetch + its hash.
    #[serde(default)]
    files: std::collections::HashMap<String, FileRef>,
}

/// A grammar as listed in the hosted catalog: its id and the extensions it
/// covers. `grove init` maps a project's files to languages through this — the
/// full set, not just what's already cached.
pub struct CatalogGrammar {
    pub name: String,
    pub extensions: Vec<String>,
}

/// Fetch the hosted catalog and return every grammar's id + extensions.
pub fn catalog_grammars() -> Result<Vec<CatalogGrammar>> {
    let host = host();
    let catalog: Catalog = serde_json::from_slice(&get_bytes(&format!("{host}/index.json"))?)
        .context("parsing index.json catalog")?;
    Ok(catalog
        .grammars
        .into_iter()
        .map(|g| CatalogGrammar { name: g.name, extensions: g.extensions })
        .collect())
}

#[derive(Deserialize)]
struct FileRef {
    sha256: String,
    /// If set, the file is a release asset of this name under `release_base`;
    /// otherwise it sits in the repo at `<host>/<lang>/<filename>`.
    #[serde(default)]
    asset: Option<String>,
}

fn host() -> String {
    std::env::var("GROVE_REGISTRY_URL")
        .unwrap_or_else(|_| DEFAULT_HOST.to_string())
        .trim_end_matches('/')
        .to_string()
}

pub(crate) fn get_bytes(url: &str) -> Result<Vec<u8>> {
    let resp = ureq::get(url)
        .call()
        .map_err(|e| anyhow!("GET {url}: {e}"))?;
    let mut buf = Vec::new();
    resp.into_reader()
        .read_to_end(&mut buf)
        .with_context(|| format!("reading {url}"))?;
    Ok(buf)
}

/// Reject any catalog-supplied name that isn't a single, safe path component.
///
/// The catalog (`index.json`) is fetched over the network and may be hostile or
/// MITM'd. A grammar `name` or filename containing `..`, a path separator, or an
/// absolute prefix would escape the cache directory once joined (path traversal,
/// arbitrary file write). We only ever write `<cache>/<lang>/<file>`, so every
/// such segment must be a plain file name — exactly one `Normal` path component
/// with no separator of either platform.
fn safe_segment(s: &str) -> Result<()> {
    use std::path::{Component, Path};
    let mut comps = Path::new(s).components();
    let single_normal =
        matches!(comps.next(), Some(Component::Normal(_))) && comps.next().is_none();
    if s.is_empty() || s.contains('/') || s.contains('\\') || !single_normal {
        bail!("catalog path segment `{s}` is not a plain file name (possible path traversal)");
    }
    Ok(())
}

/// Fetch the named languages (or all in the catalog) into the OS cache.
pub fn run(langs: &[String], force: bool) -> Result<()> {
    let host = host();
    println!("registry host: {host}\n");

    let catalog: Catalog = serde_json::from_slice(&get_bytes(&format!("{host}/index.json"))?)
        .context("parsing index.json catalog")?;

    let targets: Vec<&CatEntry> = if langs.is_empty() {
        catalog.grammars.iter().collect()
    } else {
        langs
            .iter()
            .map(|l| {
                catalog
                    .grammars
                    .iter()
                    .find(|g| &g.name == l)
                    .with_context(|| format!("`{l}` is not in the catalog at {host}"))
            })
            .collect::<Result<_>>()?
    };

    let cache = registry::cache_root().context("no OS cache directory available")?;
    let mut fetched = 0;
    for e in targets {
        safe_segment(&e.name)?;
        let dir = cache.join(&e.name);
        if dir.join("grammar.wasm").exists() && !force {
            println!("  {:<12} {} · cached", e.name, e.version);
            continue;
        }
        if e.files.is_empty() {
            bail!("catalog entry for `{}` lists no files", e.name);
        }
        // Download every file and verify its hash *before* writing any (atomic).
        let mut names: Vec<&String> = e.files.keys().collect();
        names.sort();
        let mut blobs = Vec::new();
        for fname in names {
            safe_segment(fname)?;
            let fref = &e.files[fname];
            let url = match &fref.asset {
                Some(asset) => {
                    let base = catalog
                        .release_base
                        .as_deref()
                        .context("catalog has release assets but no release_base")?;
                    format!("{base}/{asset}")
                }
                None => format!("{host}/{}/{fname}", e.name),
            };
            let bytes = get_bytes(&url)?;
            let got = sha256(&bytes);
            if got != fref.sha256 {
                bail!("{}/{fname}: hash mismatch — catalog {}, downloaded {got}", e.name, fref.sha256);
            }
            blobs.push((fname.clone(), bytes));
        }

        std::fs::create_dir_all(&dir).with_context(|| format!("creating {}", dir.display()))?;
        for (fname, bytes) in &blobs {
            std::fs::write(dir.join(fname), bytes)?;
        }
        let kb = blobs
            .iter()
            .find(|(n, _)| n == "grammar.wasm")
            .map_or(0, |(_, b)| b.len() / 1024);
        println!("  {:<12} {} ✓ {} files, {} KB", e.name, e.version, blobs.len(), kb);
        fetched += 1;
    }
    println!("\n{fetched} fetched · cache: {}", cache.display());
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::{host, safe_segment, sha256, Catalog, DEFAULT_HOST};

    #[test]
    fn host_defaults_and_honors_env_override() {
        // All env mutation kept in one test so it can't race a parallel reader.
        std::env::remove_var("GROVE_REGISTRY_URL");
        assert_eq!(host(), DEFAULT_HOST, "defaults to the hosted registry");

        std::env::set_var("GROVE_REGISTRY_URL", "https://mirror.test/grove/");
        assert_eq!(host(), "https://mirror.test/grove", "override + trailing slash trimmed");

        std::env::remove_var("GROVE_REGISTRY_URL");
    }

    #[test]
    fn catalog_parses_schema_2_with_release_assets() {
        let json = r#"{
            "schema": 2,
            "release_base": "https://example.test/releases/v1",
            "grammars": [
                { "name": "rust", "version": "0.24.0", "extensions": ["rs"],
                  "files": {
                      "grammar.wasm": { "sha256": "sha256:aa", "asset": "rust.wasm" },
                      "tags.scm": { "sha256": "sha256:bb" }
                  } }
            ]
        }"#;
        let cat: Catalog = serde_json::from_str(json).unwrap();
        assert_eq!(cat.release_base.as_deref(), Some("https://example.test/releases/v1"));
        assert_eq!(cat.grammars.len(), 1);
        let g = &cat.grammars[0];
        assert_eq!(g.name, "rust");
        assert_eq!(g.extensions, vec!["rs"]);
        assert_eq!(g.files["grammar.wasm"].asset.as_deref(), Some("rust.wasm"));
        assert_eq!(g.files["grammar.wasm"].sha256, "sha256:aa");
        assert!(g.files["tags.scm"].asset.is_none(), "repo-served file has no asset");
    }

    #[test]
    fn catalog_tolerates_missing_optional_fields() {
        let cat: Catalog = serde_json::from_str(r#"{ "grammars": [] }"#).unwrap();
        assert!(cat.release_base.is_none());
        assert!(cat.grammars.is_empty());
    }

    #[test]
    fn fetch_verifies_with_the_shared_helper() {
        // `fetch` no longer has its own digest — it verifies downloads against
        // the exact `registry::sha256` the index/lockfile were built with, so a
        // format change can't drift the producer and verifier apart (#15).
        assert_eq!(
            sha256(b""),
            "sha256:e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"
        );
        assert_eq!(sha256(b"abc"), crate::registry::sha256(b"abc"));
    }

    #[test]
    fn accepts_plain_file_names() {
        for ok in ["rust", "javascript", "c_sharp", "grammar.wasm", "tags.scm", "manifest.json"] {
            assert!(safe_segment(ok).is_ok(), "{ok} should be accepted");
        }
    }

    #[test]
    fn rejects_traversal_and_separators() {
        // Parent-dir escapes, absolute paths, nested paths, separators, and the
        // empty / dot segments must all be refused before they reach a join.
        for bad in [
            "",
            ".",
            "..",
            "../etc",
            "../../.bashrc",
            "/etc/passwd",
            "a/b",
            "a\\b",
            "..\\..\\foo",
            "foo/",
            "./foo",
        ] {
            assert!(safe_segment(bad).is_err(), "{bad:?} should be rejected");
        }
    }

    #[test]
    fn traversal_segment_does_not_escape_cache() {
        // The concrete property the guard protects: a rejected segment never gets
        // joined onto the cache root, so no write can land outside it.
        let cache = std::path::Path::new("/home/user/.cache/grove/grammars");
        let hostile = "../../../.bashrc";
        assert!(safe_segment(hostile).is_err());
        // Demonstrate why the guard matters: the unchecked join *would* escape.
        let joined = cache.join(hostile);
        assert!(!joined.starts_with(cache) || joined.components().any(|c| {
            matches!(c, std::path::Component::ParentDir)
        }));
    }
}

fn name_matches(sym_name: &str, query_lc: &str, contains: bool) -> bool {
    let sym_lc = sym_name.to_lowercase();
    if contains {
        sym_lc.contains(query_lc)
    } else {
        sym_lc == query_lc
    }
}

/// `outline` — the definitions in one file, optionally filtered by kind.
pub fn outline(file: &Path, kind: Option<&str>) -> Result<Vec<Symbol>> {
    let grammar = registry::for_path(file)?;
    let src = read(file)?;
    let mut syms = engine::extract(&grammar, &rel(file), &src)?;
    syms.retain(|s| s.is_definition && kind.is_none_or(|k| kind_matches(&s.kind, k)));
    Ok(syms)
}

/// Project symbols to a JSON array at a detail level, to keep payloads bounded:
/// 0 = terse (kind/name/parent/line), 1 = default (adds id/col/signature, drops
/// byte offsets — the agent addresses symbols by id, not offset), 2 = full.
pub fn project(syms: &[Symbol], detail: u8) -> serde_json::Value {
    use serde_json::{Map, Value};
    if detail >= 2 {
        return serde_json::to_value(syms).unwrap_or(Value::Null);
    }
    let arr = syms
        .iter()
        .map(|s| {
            let mut m = Map::new();
            if detail >= 1 {
                m.insert("id".into(), s.id.clone().into());
            }
            m.insert("kind".into(), s.kind.clone().into());
            m.insert("name".into(), s.name.clone().into());
            if let Some(p) = &s.parent {
                m.insert("parent".into(), p.clone().into());
            }
            m.insert("line".into(), s.line.into());
            if detail >= 1 {
                m.insert("col".into(), s.col.into());
                m.insert("signature".into(), s.signature.clone().into());
            }
            Value::Object(m)
        })
        .collect();
    Value::Array(arr)
}

/// `symbols` — find across a directory, gitignore-aware.
pub fn symbols(
    dir: &Path,
    kind: Option<&str>,
    name: Option<&str>,
    refs: bool,
    name_contains: bool,
) -> Result<Vec<Symbol>> {
    let name_lc = name.map(str::to_lowercase);
    let mut all = Vec::new();
    for_each_source(dir, |grammar, relpath, src| {
        for s in engine::extract(grammar, relpath, src)? {
            if !refs && !s.is_definition {
                continue;
            }
            if kind.is_some_and(|k| !kind_matches(&s.kind, k)) {
                continue;
            }
            if name_lc
                .as_ref()
                .is_some_and(|n| !name_matches(&s.name, n, name_contains))
            {
                continue;
            }
            all.push(s);
        }
        Ok(())
    })?;
    Ok(all)
}

/// The result of `source`: the chosen symbol's code, plus any other
/// definitions that shared the name (so the agent can disambiguate).
#[derive(Debug, Serialize)]
pub struct SourceResult {
    pub id: String,
    pub source: String,
    #[serde(skip_serializing_if = "Vec::is_empty")]
    pub other_candidates: Vec<String>,
}

/// `source` — full code of a symbol, by id (`<lang>:<path>#<name>@<line>`) or
/// by file + name.
pub fn source(id_or_file: &str, name: Option<&str>) -> Result<SourceResult> {
    let (file, want, want_line): (PathBuf, String, Option<usize>) = match name {
        Some(n) => (PathBuf::from(id_or_file), n.to_string(), None),
        None => {
            let rest = id_or_file.split_once(':').map_or(id_or_file, |(_, r)| r);
            let (path, after) = rest
                .split_once('#')
                .context("symbol id must look like <lang>:<path>#<name>@<line>")?;
            // The `@<line>` suffix disambiguates duplicate-named definitions; keep
            // it so the requested symbol is the one returned.
            let (name, line) = match after.split_once('@') {
                Some((n, r)) => (n.to_string(), r.parse::<usize>().ok()),
                None => (after.to_string(), None),
            };
            (PathBuf::from(path), name, line)
        }
    };

    let grammar = registry::for_path(&file)?;
    let src = read(&file)?;
    let syms = engine::extract(&grammar, &rel(&file), &src)?;
    let matches: Vec<&Symbol> = syms
        .iter()
        .filter(|s| s.is_definition && s.name == want)
        .collect();

    // Prefer the exact-line match when the id carried a line; otherwise (name
    // mode, lineless id, or no line matched) fall back to the first definition.
    let chosen = match want_line.and_then(|r| matches.iter().find(|s| s.line == r)) {
        Some(c) => *c,
        None => match matches.first() {
            None => anyhow::bail!("no definition named `{want}` in {}", file.display()),
            Some(c) => *c,
        },
    };
    Ok(SourceResult {
        id: chosen.id.clone(),
        source: engine::slice(&src, chosen).to_string(),
        other_candidates: matches
            .iter()
            .filter(|s| s.id != chosen.id)
            .map(|s| s.id.clone())
            .collect(),
    })
}

/// `check` — ERROR / MISSING nodes in one file.
pub fn check(file: &Path) -> Result<Vec<Defect>> {
    let grammar = registry::for_path(file)?;
    let src = read(file)?;
    engine::check(&grammar, &src)
}

/// A site where a symbol is referenced (call site, type use, textual occurrence).
#[derive(Debug, Serialize)]
pub struct CallSite {
    pub file: String,
    /// 1-based line and column of the call (editor / `grep -n` convention).
    pub line: usize,
    pub col: usize,
    /// The function/method that contains this reference (`Type::method` when known).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub in_function: Option<String>,
    /// The trimmed source text of the call's line.
    pub text: String,
    /// Provenance: `"structural"` for tree-sitter tag-resolved references,
    /// `"textual"` for whole-word grep matches that the tags query missed.
    /// Structural sites are high-precision (name-resolved); textual sites fill
    /// recall gaps (may include type annotations, imports, or comments).
    pub source: String,
}

/// `callers` — every reference to `name` across `dir`, with enclosing function.
///
/// Two passes are merged and deduped:
/// 1. **Structural** — tree-sitter tag-resolved references (all reference kinds:
///    call, type, implementation, etc.). High precision but low recall for names
///    that the tags query doesn't capture (e.g. class/type references in Java or
///    Python).
/// 2. **Textual** — whole-word grep for the name, for lines not already covered
///    by a structural hit. Higher recall but lower precision (may include type
///    annotations, imports, or comments). Each result carries a `source` field
///    (`"structural"` or `"textual"`) so the agent can prioritise.
///
/// Name-based: matches *any* symbol with this name (the slice does not resolve
/// receiver types). Honest over-match, documented for the agent.
pub fn callers(dir: &Path, name: &str) -> Result<Vec<CallSite>> {
    let mut out = Vec::new();
    for_each_source(dir, |grammar, relpath, src| {
        // Reuse the parse tree from extraction for the enclosing-function pass —
        // parsing dominates cost, so re-parsing here would double the work.
        let (syms, tree) = engine::extract_with_tree(grammar, relpath, src)?;
        let root = tree.root_node();

        // --- Structural pass: all non-definition tag-resolved references ---
        // The previous `is_call_kind` filter excluded type references, impl
        // references, etc., causing callers to return [] for heavily-used
        // class/type names (issue #33). Including all reference kinds fixes
        // that while the textual pass below fills the long tail.
        let structurals: Vec<&Symbol> = syms
            .iter()
            .filter(|s| !s.is_definition && s.name == name)
            .collect();
        // Lines covered by structural hits OR structural definitions of the same
        // name — the textual pass skips these to avoid duplicating references or
        // surfacing the definition line itself (callers is for references, not
        // definitions).
        let mut skip_lines: std::collections::HashSet<usize> =
            std::collections::HashSet::new();
        for s in &structurals {
            skip_lines.insert(s.line.saturating_sub(1));
        }
        for s in syms.iter().filter(|s| s.is_definition && s.name == name) {
            skip_lines.insert(s.line.saturating_sub(1));
        }
        for s in &structurals {
            out.push(CallSite {
                in_function: engine::enclosing_function_at(
                    root,
                    s.start_byte,
                    src,
                    &grammar.profile,
                ),
                file: s.file.clone(),
                line: s.line,
                col: s.col,
                text: s.signature.clone(),
                source: "structural".to_string(),
            });
        }

        // --- Textual pass: whole-word grep for the name ---
        // Covers references that the tags query misses (type annotations, imports,
        // dynamic dispatch, etc.). Only adds lines not already covered by structural
        // hits or definitions, so there's no duplication.
        let src_str = std::str::from_utf8(src).unwrap_or("");
        for (row, line_text) in src_str.lines().enumerate() {
            if skip_lines.contains(&row) {
                continue; // already covered by a structural hit or definition
            }
            if !has_whole_word(line_text, name) {
                continue;
            }
            // Find the byte offset of the first occurrence for enclosing-function.
            let col = line_text.find(name).unwrap_or(0);
            let byte = line_offset(src, row) + col;
            out.push(CallSite {
                in_function: engine::enclosing_function_at(root, byte, src, &grammar.profile),
                file: relpath.to_string(),
                line: row + 1,
                col: col + 1,
                text: line_text.trim().to_string(),
                source: "textual".to_string(),
            });
        }

        Ok(())
    })?;
    Ok(out)
}

/// Byte offset of the start of line `row` (0-based) in `source`.
fn line_offset(source: &[u8], row: usize) -> usize {
    let mut off = 0;
    for _ in 0..row {
        match source[off..].iter().position(|&b| b == b'\n') {
            Some(pos) => off += pos + 1,
            None => return source.len(),
        }
    }
    off
}

/// Does `haystack` contain `needle` as a whole word?
/// A word boundary is the start/end of `haystack` or a char that is not
/// ASCII alphanumeric or underscore. This mirrors how `grep -w` works for
/// identifier names, without requiring a regex dependency.
fn has_whole_word(haystack: &str, needle: &str) -> bool {
    let needle_bytes = needle.as_bytes();
    let haystack_bytes = haystack.as_bytes();
    if needle_bytes.is_empty() {
        return false;
    }
    let mut i = 0;
    while i + needle_bytes.len() <= haystack_bytes.len() {
        if &haystack_bytes[i..i + needle_bytes.len()] == needle_bytes {
            let before_ok = i == 0 || !is_ident_char(haystack_bytes[i - 1]);
            let after_ok =
                i + needle_bytes.len() == haystack_bytes.len()
                    || !is_ident_char(haystack_bytes[i + needle_bytes.len()]);
            if before_ok && after_ok {
                return true;
            }
        }
        // Advance: skip ahead past the current byte (handles multi-byte UTF-8
        // correctly because we only match on ASCII needle/ident chars).
        i += 1;
    }
    false
}

fn is_ident_char(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

/// Parse a `file:line:col` position string. `line`/`col` are 1-based on input
/// (the editor / `grep -n` convention grove prints), and are returned as the
/// 0-based row/col tree-sitter expects, so the location grove prints round-trips
/// straight back into `--at`.
pub fn parse_pos(s: &str) -> Result<(PathBuf, usize, usize)> {
    let parts: Vec<&str> = s.rsplitn(3, ':').collect();
    match parts.as_slice() {
        [col, line, file] => {
            let line: usize = line.parse().map_err(|_| anyhow::anyhow!("bad line in `{s}`"))?;
            let col: usize = col.parse().map_err(|_| anyhow::anyhow!("bad col in `{s}`"))?;
            Ok((
                PathBuf::from(file),
                line.saturating_sub(1),
                col.saturating_sub(1),
            ))
        }
        _ => anyhow::bail!("expected file:line:col, got `{s}`"),
    }
}

/// A definition in a `map` result, with its outgoing references.
#[derive(Debug, Serialize)]
pub struct MapEntry {
    pub id: String,
    pub kind: String,
    pub name: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub parent: Option<String>,
    pub row: usize,
    pub signature: String,
    /// Names of other symbols this definition references (outgoing edges).
    #[serde(skip_serializing_if = "Vec::is_empty")]
    pub references: Vec<String>,
}

/// A file in a `map` result, with its definitions and their references.
#[derive(Debug, Serialize)]
pub struct FileMap {
    pub file: String,
    pub entries: Vec<MapEntry>,
}

/// `map` — compact structural map of a directory: every definition grouped by
/// file, with each definition's outgoing references (which other symbols it
/// calls or uses). No source bodies — just the dependency graph. Use this
/// instead of many `symbols`+`source` calls when you need a broad picture of
/// how code connects.
pub fn map(
    dir: &Path,
    kind: Option<&str>,
    name: Option<&str>,
    name_contains: bool,
) -> Result<Vec<FileMap>> {
    let name_lc = name.map(str::to_lowercase);
    let mut file_maps = Vec::new();
    for_each_source(dir, |grammar, relpath, src| {
        let syms = engine::extract(grammar, relpath, src)?;

        // Collect matching definition indices, sorted by byte-range size
        // ascending so innermost (narrowest) definitions come first. This
        // lets us attribute each reference to its innermost enclosing def.
        let mut defs: Vec<usize> = syms
            .iter()
            .enumerate()
            .filter(|(_, s)| s.is_definition)
            .filter(|(_, s)| kind.is_none_or(|k| kind_matches(&s.kind, k)))
            .filter(|(_, s)| name_lc.as_ref().is_none_or(|n| name_matches(&s.name, n, name_contains)))
            .map(|(i, _)| i)
            .collect();
        defs.sort_by_key(|&i| syms[i].end_byte - syms[i].start_byte);

        // Attribute each reference to the innermost containing definition.
        let mut ref_map: std::collections::HashMap<usize, Vec<String>> =
            std::collections::HashMap::new();
        for (_, s) in syms.iter().enumerate() {
            if s.is_definition {
                continue;
            }
            for &d in &defs {
                if s.start_byte >= syms[d].start_byte && s.end_byte <= syms[d].end_byte {
                    ref_map.entry(d).or_default().push(s.name.clone());
                    break; // first (narrowest) match wins
                }
            }
        }

        // Deduplicate reference names per definition.
        for names in ref_map.values_mut() {
            names.sort();
            names.dedup();
        }

        // Build entries, sorted by row for deterministic output.
        let mut entries: Vec<MapEntry> = defs
            .iter()
            .map(|&d| {
                let s = &syms[d];
                let mut refs = ref_map.remove(&d).unwrap_or_default();
                // Remove self-references (e.g. recursive calls).
                refs.retain(|n| n != &s.name);
                MapEntry {
                    id: s.id.clone(),
                    kind: s.kind.clone(),
                    name: s.name.clone(),
                    parent: s.parent.clone(),
                    row: s.line,
                    signature: s.signature.clone(),
                    references: refs,
                }
            })
            .collect();
        entries.sort_by_key(|e| e.row);

        if !entries.is_empty() {
            file_maps.push(FileMap {
                file: relpath.to_string(),
                entries,
            });
        }
        Ok(())
    })?;
    file_maps.sort_by(|a, b| a.file.cmp(&b.file));
    Ok(file_maps)
}

/// `definition` — exact-name definitions of `name` across `dir` (go-to-def).
pub fn definition(dir: &Path, name: &str) -> Result<Vec<Symbol>> {
    // `name_contains = false`: `definition` is exact by contract, so pre-filter
    // exactly — cheaper than pulling every substring hit then retaining.
    let mut defs = symbols(dir, None, Some(name), false, false)?;
    defs.retain(|s| s.name == name);
    Ok(defs)
}

/// `definition --at` — resolve the identifier at a usage site, then find its
/// definition(s). `row`/`col` are 0-based tree-sitter coords (callers feed the
/// output of [`parse_pos`], which converts the 1-based `file:line:col` users
/// type). Returns the resolved name alongside the matches.
pub fn definition_at(file: &Path, row: usize, col: usize, dir: &Path) -> Result<(String, Vec<Symbol>)> {
    let grammar = registry::for_path(file)?;
    let src = read(file)?;
    let name = engine::with_tree(&grammar, &src, |root, profile| {
        engine::identifier_at(root, row, col, &src, profile)
    })?
    .with_context(|| format!("no identifier at {}:{row}:{col}", file.display()))?;
    // Scope-aware first (ADR 0001 Step 1): if the cursor's identifier binds to a
    // local definition in an enclosing scope, that single binding *is* the
    // answer — a shadowing local must win over a same-named global. Only when
    // there is no local binding do we fall back to the directory-wide name
    // lookup (the historical behavior, also the floor for free/global names).
    if let Some(local) = engine::resolve_local_at(&grammar, &rel(file), &src, row, col)? {
        return Ok((name, vec![local]));
    }
    // Import-edge next (ADR 0001 Step 2): if the name is brought in by an import,
    // resolve it to the definition in the target file — cross-file go-to-def
    // without an index. Falls through to directory-wide lookup on any miss.
    let imported = resolve_import_at(file, &name, dir, &grammar, &src)?;
    if !imported.is_empty() {
        return Ok((name, imported));
    }
    let defs = definition(dir, &name)?;
    Ok((name, defs))
}

/// Resolve `name` to a definition in the file an import binds it from. Returns an
/// empty vec when the language has no import-resolution strategy, `name` isn't
/// imported here, the module doesn't resolve to a file on disk, or that file has
/// no matching top-level definition — every case the caller treats as "fall back
/// to directory-wide lookup". Parses at most one extra file (the target), so the
/// whole operation stays stateless and bounded by import depth, not repo size.
fn resolve_import_at(
    file: &Path,
    name: &str,
    dir: &Path,
    grammar: &Grammar,
    src: &[u8],
) -> Result<Vec<Symbol>> {
    let Some(strategy) = grammar.profile.import_resolution.as_deref() else {
        return Ok(Vec::new());
    };
    let Some(binding) = engine::extract_imports(grammar, src)?
        .into_iter()
        .find(|b| b.name == name)
    else {
        return Ok(Vec::new());
    };
    for cand in import_candidate_paths(strategy, &binding.module, file, dir) {
        if !cand.is_file() {
            continue;
        }
        let tsrc = read(&cand)?;
        let trel = rel(&cand);
        let defs: Vec<Symbol> = engine::extract(grammar, &trel, &tsrc)?
            .into_iter()
            .filter(|s| s.is_definition && s.name == binding.source)
            .collect();
        if !defs.is_empty() {
            return Ok(defs);
        }
    }
    Ok(Vec::new())
}

/// Candidate file paths a module path could resolve to, by strategy. The first
/// that exists and contains the imported definition wins. Pure path arithmetic —
/// no IO here.
fn import_candidate_paths(
    strategy: &str,
    module: &str,
    current_file: &Path,
    dir: &Path,
) -> Vec<PathBuf> {
    match strategy {
        // Python: `foo.bar` → `<root>/foo/bar.py` | `<root>/foo/bar/__init__.py`.
        // Leading dots are relative to the current file's package: one dot = the
        // file's own directory, each extra dot climbs one more.
        "dotted_package" => {
            let dots = module.chars().take_while(|&c| c == '.').count();
            let rest = &module[dots..];
            let parts: Vec<&str> = rest.split('.').filter(|p| !p.is_empty()).collect();
            let mut base = if dots == 0 {
                dir.to_path_buf()
            } else {
                let mut b = current_file.parent().unwrap_or(dir).to_path_buf();
                for _ in 0..dots.saturating_sub(1) {
                    b = b.parent().map(Path::to_path_buf).unwrap_or(b);
                }
                b
            };
            for p in &parts {
                base.push(p);
            }
            vec![base.with_extension("py"), base.join("__init__.py")]
        }
        // JS/TS: only relative specifiers resolve to a file; bare specifiers
        // (`react`) are package imports we don't chase. `./util` → `./util.js` |
        // `./util.jsx` | `./util/index.js`.
        "relative_path" => {
            if !module.starts_with('.') {
                return Vec::new();
            }
            let joined = normalize(&current_file.parent().unwrap_or(dir).join(module));
            if joined.extension().is_some() {
                return vec![joined];
            }
            vec![
                joined.with_extension("js"),
                joined.with_extension("jsx"),
                joined.join("index.js"),
            ]
        }
        _ => Vec::new(),
    }
}

/// Lexically normalize a path, resolving `.` and `..` without touching the disk
/// (so `a/b/../util` → `a/util`). Symlink-blind, which is fine for module paths.
fn normalize(path: &Path) -> PathBuf {
    use std::path::Component;
    let mut out = PathBuf::new();
    for comp in path.components() {
        match comp {
            Component::CurDir => {}
            Component::ParentDir => {
                out.pop();
            }
            other => out.push(other.as_os_str()),
        }
    }
    out
}

